use std::collections::HashMap;

#[derive(Clone)]
struct Profile {
    username: String,
    email: String,
}

fn process_user_ids(user_ids: &[u32], fetcher: impl Fn(u32) -> Option<Profile>) -> HashMap<u32, Profile> {
    let mut results = HashMap::new();
    for &id in user_ids {
        if let Some(profile) = fetcher(id) {
            results.insert(id, profile);
        }
    }
    results
}

fn main() {
    let mock_data: HashMap<u32, Profile> = [
        (101, Profile { username: "alice".to_string(), email: "a@corp.com".to_string() }),
        (102, Profile { username: "bob".to_string(), email: "b@corp.com".to_string() }),
        (103, Profile { username: "charlie".to_string(), email: "c@corp.com".to_string() }),
    ].iter().map(|(k, v)| (*k, v.clone())).collect();

    let user_list = vec![102, 101, 99];

    let data_fetcher = |id: u32| -> Option<Profile> {
        mock_data.get(&id).cloned()
    };

    let final_profiles = process_user_ids(&user_list, data_fetcher);

    println!("Successfully retrieved {} profiles.", final_profiles.len());
    for (id, profile) in &final_profiles {
        println!("ID: {}, User: {}", id, profile.username);
    }
}

use std::collections::HashMap;
use std::sync::Arc;

struct DataChunk {
    id: u32,
    data: Vec<f32>,
}

fn process_chunk(chunk: &DataChunk) -> f32 {
    if chunk.data.is_empty() {
        return 0.0;
    }
    let sum: f32 = chunk.data.iter().sum();
    sum / (chunk.data.len() as f32)
}

fn main() {
    let mut store: HashMap<u32, Arc<DataChunk>> = HashMap::new();

    store.insert(101, Arc::new(DataChunk { id: 101, data: vec![1.0, 2.0, 3.0] }));
    store.insert(102, Arc::new(DataChunk { id: 102, data: vec![5.0, 6.0] }));

    let keys_to_process: Vec<u32> = store.keys().cloned().collect();
    let mut results: HashMap<u32, f32> = HashMap::new();

    for key in keys_to_process {
        let chunk_arc = Arc::clone(&store[&key]);
        let result = process_chunk(&chunk_arc);
        results.insert(key, result);
    }

    println!("Processed results: {:?}", results);
}

use std::collections::VecDeque;
use std::time::{Duration, Instant};

struct InputPacket {
    data: Vec<u8>,
    timestamp: Instant,
}

fn process_packets(packets: &VecDeque<InputPacket>, condition: impl Fn(&InputPacket) -> bool, mut action: impl FnMut(&InputPacket) -> bool) -> Result<(), String> {
    for packet in packets.iter() {
        if condition(packet) {
            let should_continue = action(packet);
            if !should_continue {
                return Ok(());
            }
        }
    }
    Ok(())
}

fn main() {
    let mut queue: VecDeque<InputPacket> = VecDeque::new();
    queue.push_back(InputPacket { data: vec![0x01, 0xAA], timestamp: Instant::now() - Duration::from_millis(10) });
    queue.push_back(InputPacket { data: vec![0x02, 0xBB], timestamp: Instant::now() - Duration::from_millis(5) });
    queue.push_back(InputPacket { data: vec![0xFF, 0xCC], timestamp: Instant::now() });

    let packet_condition = |packet: &InputPacket| -> bool {
        packet.data.len() == 3 && packet.data[0] == 0xFF
    };

    let mut processing_action = |packet: &InputPacket| -> bool {
        println!("Processing critical data at time {:?}", packet.timestamp);
        true
    };

    match process_packets(&queue, packet_condition, &mut processing_action) {
        Ok(_) => println!("Finished processing queue successfully."),
        Err(e) => eprintln!("Error during processing: {}", e),
    }
}

use std::ops::Mul;

struct Point {
    x: f64,
    y: f64,
}

fn calculate_total_distance(points: &[Point]) -> f64 {
    if points.len() < 2 {
        return 0.0;
    }

    let distances = (1..points.len()).map(|i| {
        let p1 = &points[i - 1];
        let p2 = &points[i];
        ((p2.x - p1.x).powi(2) + (p2.y - p1.y).powi(2)).sqrt()
    });

    distances.sum()
}

fn main() {
    let points_data = vec![ 
        Point { x: 0.0, y: 0.0 }, 
        Point { x: 3.0, y: 4.0 }, 
        Point { x: 6.0, y: 8.0 }, 
        Point { x: 10.0, y: 12.0 } 
    ];

    let total_distance = calculate_total_distance(&points_data);
    println!("Total sequential distance: {:.2}", total_distance);
}

use std::collections::HashMap;
use std::hash::{Hash, Hasher};

struct FileChunk { 
    data: Vec<u8>,
    size: usize,
}

fn process_file(chunks: Vec<FileChunk>, processing_logic: impl Fn(&Vec<u8>) -> u64) -> HashMap<u64, usize> {
    let mut seen_hashes = HashMap::new();

    for chunk in chunks {
        let hash_value = (processing_logic(&chunk.data)) as u64;
        if !seen_hashes.contains_key(&hash_value) {
            seen_hashes.insert(hash_value, chunk.size);
        }
    }
    seen_hashes
}

fn main() {
    let raw_data1 = b"applechunkdata";
    let raw_data2 = b"appl
";
    let raw_data3 = b"echunkdata";

    let chunk1 = FileChunk { data: raw_data1.to_vec(), size: raw_data1.len() };
    let chunk2 = FileChunk { data: raw_data2.to_vec(), size: raw_data2.len() };
    let chunk3 = FileChunk { data: raw_data3.to_vec(), size: raw_data3.len() };

    let chunks_set1 = vec![chunk1, chunk2, chunk3];
    let chunks_set2 = vec![FileChunk { data: b"applechunkdata".to_vec(), size: 14 }, FileChunk { data: b"appl".to_vec(), size: 4 }];

    let processing_fn = |data: &Vec<u8>| -> u64 {
        let mut hasher = std::collections::hash_map::DefaultHasher::new();
        data.hash(&mut hasher);
        hasher.finish()
    };

    let result1 = process_file(chunks_set1, processing_fn);
    println!("Deduplication run 1 found {} unique hashes.", result1.len());

    let result2 = process_file(chunks_set2, processing_fn);
    println!("Deduplication run 2 found {} unique hashes.", result2.len());
}
